REASONING_RELATED = {"chain-of-thought", "think-step-by-step", "self-critique"}

def score_technique(name, year_introduced, model_native_in):
    if model_native_in is None:
        return {
            "verdict": "still useful",
            "reason": "model has not absorbed this natively",
        }
    if model_native_in <= 2025:
        if name in REASONING_RELATED:
            return {
                "verdict": "redundant",
                "reason": f"model does this internally since {model_native_in}",
            }
        return {
            "verdict": "counterproductive",
            "reason": f"native API exists since {model_native_in}; prompt-level version conflicts",
        }
    return {
        "verdict": "context-dependent",
        "reason": "depends on model class",
    }

cot = score_technique("chain-of-thought", year_introduced=2022, model_native_in=2024)
sos = score_technique("structured-output-schema", year_introduced=2023, model_native_in=2024)
print(f"chain-of-thought: {cot}")
print(f"structured-output-schema: {sos}")

REASONING_RELATED = {"chain-of-thought", "think-step-by-step", "self-critique"}

techniques = [
    {"name": "chain-of-thought",          "year_introduced": 2022, "model_native_in": 2024},
    {"name": "few-shot-examples",         "year_introduced": 2020, "model_native_in": None},
    {"name": "structured-output-schema",  "year_introduced": 2023, "model_native_in": 2024},
    {"name": "self-critique",             "year_introduced": 2023, "model_native_in": 2025},
    {"name": "multi-tool-orchestration",  "year_introduced": 2024, "model_native_in": 2027},
]

def verdict_for(t):
    native = t["model_native_in"]
    if native is None:
        return "still useful"
    if native <= 2025:
        if t["name"] in REASONING_RELATED:
            return "redundant"
        return "counterproductive"
    return "context-dependent"

def audit_prompts(techniques):
    verdicts = {t["name"]: verdict_for(t) for t in techniques}
    counts = {
        "still useful": 0,
        "redundant": 0,
        "counterproductive": 0,
        "context-dependent": 0,
    }
    for v in verdicts.values():
        counts[v] += 1
    return {"verdicts": verdicts, "counts": counts}

result = audit_prompts(techniques)
print(f"verdicts: {result['verdicts']}")
print(f"counts: {result['counts']}")
